//! Release & channel storage (Tower 2).
//!
//! L2 **component releases** (one entity's versioned parts), L1 **vehicle
//! releases** (a tagged combination of component releases — the desired
//! whole-vehicle state), and **channel** pointers. Resolving a channel yields
//! the desired [`wire::Tree`]; the per-vehicle *campaign* to reach it is
//! generated by [`wire::flash_plan`], not stored here.
//!
//! Releases are **content-identified**: a component's identity is the hash of
//! its parts, a vehicle's identity is the hash of its member set. Creating a
//! release is therefore idempotent — the same content reuses the existing
//! release (whatever its version), so a reconcile only cuts a new version when
//! the content actually changed. The `version` is just a human label (a build
//! number); `created_at` is the build time (when this content was first cut).

use axum::extract::{Path, State};
use axum::Json;
use serde::{Deserialize, Serialize};
use sqlx::postgres::PgRow;
use sqlx::{PgPool, Row};
use wire::{ArtifactRef, ContentHash, Entity, Part, Tree};

use crate::content::{AppError, AppState};

// --- request / response bodies ---------------------------------------------

/// `POST /admin/component-releases` body — one entity's versioned parts.
#[derive(Deserialize)]
pub struct NewComponentRelease {
    pub entity_path: String,
    pub entity_kind: String,
    pub version: String,
    pub parts: Vec<NewPart>,
}

#[derive(Deserialize)]
pub struct NewPart {
    pub id: String,
    pub kind: String,
    pub content: ContentHash,
}

/// `POST /admin/vehicle-releases` body — a tagged combination of component
/// releases (the desired whole-vehicle state).
#[derive(Deserialize)]
pub struct NewVehicleRelease {
    pub tag: String,
    pub version: String,
    pub members: Vec<i64>,
}

/// `PUT /admin/channels/{name}` body.
#[derive(Deserialize)]
pub struct SetChannel {
    pub vehicle_release_id: i64,
}

/// A resolved release. `reused` is true when the content already had a release
/// (so the proposed version was ignored and the existing one returned).
#[derive(Serialize)]
pub struct ReleaseRef {
    pub id: i64,
    pub version: String,
    pub created_at: String,
    pub reused: bool,
}

impl ReleaseRef {
    fn from_row(row: &PgRow, reused: bool) -> Self {
        ReleaseRef {
            id: row.get("id"),
            version: row.get("version"),
            created_at: row.get("created_at"),
            reused,
        }
    }
}

/// `GET /admin/channels/{name}` response — the channel's current vehicle release
/// (the build-number source for a reconcile), or `null` if unset.
#[derive(Serialize)]
pub struct ChannelState {
    pub name: String,
    pub vehicle: Option<VehicleRef>,
}

#[derive(Serialize)]
pub struct VehicleRef {
    pub id: i64,
    pub tag: String,
    pub version: String,
    pub created_at: String,
}

// --- handlers --------------------------------------------------------------

/// `POST /admin/component-releases` — mint an L2 component release, idempotent on
/// content. Same parts as an existing release for this entity → that release is
/// returned (`reused`); otherwise a new one is cut with the proposed `version`.
pub async fn create_component_release(
    State(s): State<AppState>,
    Json(req): Json<NewComponentRelease>,
) -> Result<Json<ReleaseRef>, AppError> {
    let pool = s.pool()?;
    let identity = component_identity(&req.entity_kind, &req.parts);

    if let Some(row) = sqlx::query(
        "SELECT id, version, created_at::text AS created_at FROM component_releases \
         WHERE entity_path = $1 AND identity_hash = $2",
    )
    .bind(&req.entity_path)
    .bind(&identity)
    .fetch_optional(pool)
    .await
    .map_err(db)?
    {
        return Ok(Json(ReleaseRef::from_row(&row, true)));
    }

    let row = sqlx::query(
        "INSERT INTO component_releases (entity_path, entity_kind, version, identity_hash) \
         VALUES ($1, $2, $3, $4) RETURNING id, version, created_at::text AS created_at",
    )
    .bind(&req.entity_path)
    .bind(&req.entity_kind)
    .bind(&req.version)
    .bind(&identity)
    .fetch_one(pool)
    .await
    .map_err(db)?;
    let id: i64 = row.get("id");

    for p in &req.parts {
        sqlx::query(
            "INSERT INTO component_release_parts (release_id, part_id, part_kind, content_hash) \
             VALUES ($1, $2, $3, $4)",
        )
        .bind(id)
        .bind(&p.id)
        .bind(&p.kind)
        .bind(p.content.to_prefixed())
        .execute(pool)
        .await
        .map_err(db)?;
    }
    Ok(Json(ReleaseRef::from_row(&row, false)))
}

/// `POST /admin/vehicle-releases` — mint an L1 vehicle release (the desired
/// whole-vehicle state), idempotent on content. Same member set for this tag →
/// that release is returned (`reused`); otherwise a new one is cut.
pub async fn create_vehicle_release(
    State(s): State<AppState>,
    Json(req): Json<NewVehicleRelease>,
) -> Result<Json<ReleaseRef>, AppError> {
    let pool = s.pool()?;
    let identity = vehicle_identity(&req.members);

    if let Some(row) = sqlx::query(
        "SELECT id, version, created_at::text AS created_at FROM vehicle_releases \
         WHERE tag = $1 AND identity_hash = $2",
    )
    .bind(&req.tag)
    .bind(&identity)
    .fetch_optional(pool)
    .await
    .map_err(db)?
    {
        return Ok(Json(ReleaseRef::from_row(&row, true)));
    }

    let row = sqlx::query(
        "INSERT INTO vehicle_releases (tag, version, identity_hash) \
         VALUES ($1, $2, $3) RETURNING id, version, created_at::text AS created_at",
    )
    .bind(&req.tag)
    .bind(&req.version)
    .bind(&identity)
    .fetch_one(pool)
    .await
    .map_err(db)?;
    let id: i64 = row.get("id");

    for m in &req.members {
        sqlx::query(
            "INSERT INTO vehicle_release_members (vehicle_release_id, component_release_id) \
             VALUES ($1, $2)",
        )
        .bind(id)
        .bind(m)
        .execute(pool)
        .await
        .map_err(db)?;
    }
    Ok(Json(ReleaseRef::from_row(&row, false)))
}

/// `PUT /admin/channels/{name}` — point a channel at a vehicle release.
pub async fn set_channel(
    State(s): State<AppState>,
    Path(name): Path<String>,
    Json(req): Json<SetChannel>,
) -> Result<(), AppError> {
    let pool = s.pool()?;
    sqlx::query(
        "INSERT INTO channels (name, vehicle_release_id, updated_at) VALUES ($1, $2, now()) \
         ON CONFLICT (name) DO UPDATE SET vehicle_release_id = $2, updated_at = now()",
    )
    .bind(&name)
    .bind(req.vehicle_release_id)
    .execute(pool)
    .await
    .map_err(db)?;
    Ok(())
}

/// `GET /admin/channels/{name}` — the channel's current vehicle release, or a
/// null `vehicle` if the channel is unset/unknown. A reconcile reads this to
/// derive the next build number.
pub async fn get_channel(
    State(s): State<AppState>,
    Path(name): Path<String>,
) -> Result<Json<ChannelState>, AppError> {
    let pool = s.pool()?;
    let row = sqlx::query(
        "SELECT v.id, v.tag, v.version, v.created_at::text AS created_at \
         FROM channels c JOIN vehicle_releases v ON v.id = c.vehicle_release_id \
         WHERE c.name = $1",
    )
    .bind(&name)
    .fetch_optional(pool)
    .await
    .map_err(db)?;

    let vehicle = row.map(|r| VehicleRef {
        id: r.get("id"),
        tag: r.get("tag"),
        version: r.get("version"),
        created_at: r.get("created_at"),
    });
    Ok(Json(ChannelState { name, vehicle }))
}

/// `GET /channels/{name}/tree` — resolve a channel to its desired tree.
pub async fn channel_tree(
    State(s): State<AppState>,
    Path(name): Path<String>,
) -> Result<Json<Tree>, AppError> {
    let tree = resolve_channel(s.pool()?, &name)
        .await
        .map_err(db)?
        .ok_or(AppError::NotFound)?;
    Ok(Json(tree))
}

/// `GET /admin/artifacts/{inner}` — does Tower 2 already have this content?
/// `200` + the ref if stored, `404` if not — so a build step can skip the upload.
pub async fn artifact_exists(
    State(s): State<AppState>,
    Path(inner): Path<String>,
) -> Result<Json<ArtifactRef>, AppError> {
    let inner: ContentHash = inner.parse().map_err(|_| AppError::BadHash)?;
    match s.index.get(&inner).await? {
        Some(e) => Ok(Json(ArtifactRef {
            inner: e.inner,
            outer: e.outer,
            size: e.size,
        })),
        None => Err(AppError::NotFound),
    }
}

// --- identity --------------------------------------------------------------

/// A component release's content identity: a hash over its entity kind and its
/// parts (sorted by id, so order doesn't matter). Two releases with the same
/// identity have byte-identical content.
fn component_identity(entity_kind: &str, parts: &[NewPart]) -> String {
    let mut sorted: Vec<&NewPart> = parts.iter().collect();
    sorted.sort_by(|a, b| a.id.cmp(&b.id));

    let mut buf = String::new();
    buf.push_str(entity_kind);
    buf.push('\n');
    for p in sorted {
        buf.push_str(&p.id);
        buf.push('\0');
        buf.push_str(&p.kind);
        buf.push('\0');
        buf.push_str(&p.content.to_prefixed());
        buf.push('\n');
    }
    ContentHash::of(buf.as_bytes()).to_prefixed()
}

/// A vehicle release's content identity: a hash over its (sorted, deduped)
/// member component-release ids. Member ids are themselves content-deduped, so
/// the same whole-vehicle content yields the same identity.
fn vehicle_identity(members: &[i64]) -> String {
    let mut sorted = members.to_vec();
    sorted.sort_unstable();
    sorted.dedup();
    let joined = sorted
        .iter()
        .map(|m| m.to_string())
        .collect::<Vec<_>>()
        .join(",");
    ContentHash::of(joined.as_bytes()).to_prefixed()
}

// --- resolution ------------------------------------------------------------

/// Resolve a channel to its desired [`wire::Tree`]: channel → vehicle release →
/// member component releases → their entities + parts. `None` when the channel
/// is unset or unknown.
async fn resolve_channel(pool: &PgPool, name: &str) -> sqlx::Result<Option<Tree>> {
    let Some(vehicle_id) = channel_vehicle(pool, name).await? else {
        return Ok(None);
    };
    let members = sqlx::query(
        "SELECT component_release_id FROM vehicle_release_members WHERE vehicle_release_id = $1",
    )
    .bind(vehicle_id)
    .fetch_all(pool)
    .await?;

    let mut tree = Tree::default();
    for m in members {
        let rid: i64 = m.get("component_release_id");
        let row = sqlx::query(
            "SELECT entity_path, entity_kind, version FROM component_releases WHERE id = $1",
        )
        .bind(rid)
        .fetch_one(pool)
        .await?;
        let path: String = row.get("entity_path");
        let mut entity = Entity {
            kind: row.get("entity_kind"),
            version: Some(row.get("version")),
            update_mode: None,
            parts: Vec::new(),
        };
        let parts =
            sqlx::query("SELECT part_id, part_kind, content_hash FROM component_release_parts WHERE release_id = $1")
                .bind(rid)
                .fetch_all(pool)
                .await?;
        for p in parts {
            let content: String = p.get("content_hash");
            let Ok(content) = content.parse::<ContentHash>() else {
                continue;
            };
            entity.parts.push(Part {
                kind: p.get("part_kind"),
                id: p.get("part_id"),
                content,
            });
        }
        tree.entities.insert(path, entity);
    }
    Ok(Some(tree))
}

async fn channel_vehicle(pool: &PgPool, name: &str) -> sqlx::Result<Option<i64>> {
    let row = sqlx::query("SELECT vehicle_release_id FROM channels WHERE name = $1")
        .bind(name)
        .fetch_optional(pool)
        .await?;
    Ok(row.and_then(|r| r.get::<Option<i64>, _>("vehicle_release_id")))
}

/// Map a database error into an `AppError`.
fn db(e: sqlx::Error) -> AppError {
    AppError::Internal(e.into())
}

#[cfg(test)]
mod tests {
    use super::*;

    fn part(id: &str, kind: &str, content: &str) -> NewPart {
        NewPart {
            id: id.into(),
            kind: kind.into(),
            content: ContentHash::of(content.as_bytes()),
        }
    }

    #[test]
    fn component_identity_ignores_part_order() {
        let a = vec![part("kernel", "bank", "k"), part("rootfs", "bank", "r")];
        let b = vec![part("rootfs", "bank", "r"), part("kernel", "bank", "k")];
        assert_eq!(
            component_identity("bank", &a),
            component_identity("bank", &b)
        );
    }

    #[test]
    fn component_identity_tracks_content_kind_and_partset() {
        let base = vec![part("kernel", "bank", "k1")];
        // content change
        assert_ne!(
            component_identity("bank", &base),
            component_identity("bank", &[part("kernel", "bank", "k2")])
        );
        // added part
        assert_ne!(
            component_identity("bank", &base),
            component_identity(
                "bank",
                &[part("kernel", "bank", "k1"), part("rootfs", "bank", "r")]
            )
        );
        // entity kind change
        assert_ne!(
            component_identity("bank", &base),
            component_identity("rt", &base)
        );
    }

    #[test]
    fn vehicle_identity_ignores_order_and_dupes() {
        assert_eq!(vehicle_identity(&[1, 2, 3]), vehicle_identity(&[3, 2, 1]));
        assert_eq!(
            vehicle_identity(&[1, 2, 2, 3]),
            vehicle_identity(&[1, 2, 3])
        );
        assert_ne!(vehicle_identity(&[1, 2]), vehicle_identity(&[1, 2, 3]));
    }
}
